text:
@mixin toast-notification-base {
  @include reset;

  display: flex;
  block-size: auto;
  box-shadow: 0 2px 6px 0 rgba(0, 0, 0, 0.2);
  color: $text-inverse;
  inline-size: convert.to-rem(288px);
  padding-inline-start: convert.to-rem(13px);

  @include breakpoint(max) {
    inline-size: convert.to-rem(352px);
  }
}

[role=search],
[role=group] {
  display: inline-flex;
  position: relative;
  width: 100%;
  margin-bottom: var(--pico-spacing);
  border-radius: var(--pico-border-radius);
  box-shadow: var(--pico-group-box-shadow, 0 0 0 rgba(0, 0, 0, 0));
  vertical-align: middle;
  transition: box-shadow var(--pico-transition);
}

@mixin bx--snippet {
  @include type-style('code-01');

  position: relative;
  background-color: $layer;
  inline-size: 100%;
  max-inline-size: convert.to-rem(768px);
  // Allow shrinking in grid/flex parents so long pre content does not force layout width
  min-inline-size: 0;
}

[class*=hint--][aria-label]:after {
  content: attr(aria-label);
}
[class*=hint--][data-hint]:after {
  content: attr(data-hint);
}

[aria-label=""]:before, [aria-label=""]:after,
[data-hint=""]:before,
[data-hint=""]:after {
  display: none !important;
}

@-moz-document url-prefix() {
  [type=date],
  [type=datetime-local],
  [type=month],
  [type=time],
  [type=week] {
    padding-right: var(--pico-form-element-spacing-horizontal) !important;
    background-image: none !important;
  }
}
[dir=rtl] :is([type=date], [type=datetime-local], [type=month], [type=time], [type=week]) {
  text-align: right;
}

aside nav,
aside ol,
aside ul,
aside li {
  display: block;
}
aside li {
  padding: calc(var(--pico-nav-element-spacing-vertical) * 0.5) var(--pico-nav-element-spacing-horizontal);
}
aside li a {
  display: block;
}
aside li [role=button] {
  margin: inherit;
}

progress::-webkit-progress-bar {
  border-radius: var(--pico-border-radius);
  background: none;
}
progress[value]::-webkit-progress-value {
  background-color: var(--pico-progress-color);
  -webkit-transition: inline-size var(--pico-transition);
  transition: inline-size var(--pico-transition);
}
progress::-moz-progress-bar {
  background-color: var(--pico-progress-color);
}

[aria-label][data-balloon-pos][data-balloon-pos="left"]:after, [aria-label][data-balloon-pos][data-balloon-pos="left"]:before {
    right: 100%;
    top: 50%;
    transform: translate(var(--balloon-move), -50%); }
  [aria-label][data-balloon-pos][data-balloon-pos="left"]:after {
    margin-right: 10px; }
  [aria-label][data-balloon-pos][data-balloon-pos="left"]:before {
    width: 0;
    height: 0;
    border: 5px solid transparent;
    border-left-color: var(--balloon-color); }
